private fun primaryBtnModifier(accent: Color) =
    Modifier
        .fontFamily("'JetBrains Mono'", "monospace")
        .fontSize(0.9.cssRem)           // ↑ was 0.78
        .letterSpacing(0.1.cssRem)
        .textTransform(TextTransform.Uppercase)
        .padding(leftRight = 1.8.cssRem, topBottom = 0.9.cssRem)
        .backgroundColor(accent)
        .color(Colors.Black)
        .border(0.px)
        .borderRadius(0.px)
        .cursor(Cursor.Pointer)
        .textDecorationLine(TextDecorationLine.None)
        .display(DisplayStyle.InlineBlock)

private fun ghostBtnModifier(accent: Color) =
    Modifier
        .fontFamily("'JetBrains Mono'", "monospace")
        .fontSize(0.9.cssRem)           // ↑ was 0.78
        .letterSpacing(0.1.cssRem)
        .textTransform(TextTransform.Uppercase)
        .padding(leftRight = 1.8.cssRem, topBottom = 0.9.cssRem)
        .backgroundColor(Colors.Transparent)
        .color(accent)
        .border(1.px, LineStyle.Solid, accent)
        .borderRadius(0.px)
        .cursor(Cursor.Pointer)
        .textDecorationLine(TextDecorationLine.None)
        .display(DisplayStyle.InlineBlock)

