// ─── Page ──────────────────────────────────────────────────────────────────────

@InitRoute
fun initHomePage(ctx: InitRouteContext) {
    ctx.data.add(PageLayoutData("Home"))
}

@Page
@Layout(".components.layouts.PageLayout")
@Composable
fun HomePage() {
    val sitePalette = ColorMode.current.toSitePalette()
    val accent = sitePalette.brand.accent
    val colorMode = ColorMode.current
    val ctx = rememberPageContext()

    val border      = if (colorMode.isLight) Color.rgba(0, 0, 0, 35)  else Color.rgba(255, 255, 255, 20)
    val borderFaint = if (colorMode.isLight) Color.rgba(0, 0, 0, 15)  else Color.rgba(255, 255, 255, 8)
    val codeBg      = if (colorMode.isLight) Color.rgba(0, 0, 0, 4)   else Color.rgba(255, 255, 255, 3)

    Column(Modifier.fillMaxWidth()) {

        // ── Hero ──────────────────────────────────────────────────────────────
        Div(HeroWrapStyle.toAttrs()) {
            Div(attrs = Modifier
                .fillMaxWidth()
                .display(DisplayStyle.Flex)
                .flexDirection(FlexDirection.Row)
                .alignItems(org.jetbrains.compose.web.css.AlignItems.Center)
                .justifyContent(JustifyContent.SpaceBetween)
                .gap(4.cssRem)
                .flexWrap(FlexWrap.Wrap)
                .toAttrs()
            ) {
                Div(attrs = Modifier.flex(1).minWidth(280.px).toAttrs()) {
                    P(HeroTaglineStyle.toAttrs()) { Text("Android Engineer · Startup Founder · Pune, India") }

                    Div(HeroH1Style.toAttrs()) {
                        SpanText("Building apps")
                        Br {}
                        SpanText("that live")
                        Br {}
                        SpanText("on the device.", Modifier.color(accent))
                    }

                    P(HeroSubStyle.toAttrs()) {
                        Text(
                            "2 years. 65,000 organic users. Three shipped apps. " +
                                    "On-device LLMs, offline-first sync, and zero cloud dependencies. " +
                                    "Co-founded Genzopia Solutions and owned every layer: product, architecture, monetization."
                        )
                    }

                    Div(HeroCtaStyle.toAttrs()) {
                        Button(
                            attrs = primaryBtnModifier(accent)
                                .onClick { ctx.router.tryRoutingTo("/about") }
                                .toAttrs()
                        ) { Text("See the work") }
                        A(
                            href = "https://github.com/samrudha01codespace",
                            attrs = ghostBtnModifier(accent).toAttrs()
                        ) { Text("GitHub ↗") }
                        A(
                            href = "mailto:samrudhakshirsagar@gmail.com",
                            attrs = quietLinkModifier().toAttrs()
                        ) { Text("samrudhakshirsagar@gmail.com") }
                    }
                }

                Div(attrs = Modifier
                    .width(300.px)
                    .height(300.px)
                    .minWidth(300.px)
                    .borderRadius(50.percent)
                    .border(2.px, LineStyle.Solid, accent)
                    .padding(5.px)
                    .toAttrs()
                ) {
                    Img(
                        src = "/samrudha.jpeg",
                        alt = "Samrudha Kshirsagar",
                        attrs = Modifier
                            .width(100.percent)
                            .height(100.percent)
                            .borderRadius(50.percent)
                            .styleModifier {
                                property("object-fit", "cover")
                                property("display", "block")
                            }
                            .toAttrs()
                    )
                }
            }
        }

        // ── Divider ───────────────────────────────────────────────────────────
        Div(DividerLabelStyle.toAttrs()) {
            Div(attrs = Modifier.flex(1).height(1.px).backgroundColor(border).toAttrs()) {}
            Span(DividerTextStyle.toAttrs()) { Text("What I actually believe") }
            Div(attrs = Modifier.flex(1).height(1.px).backgroundColor(border).toAttrs()) {}
        }

        // ── Problem section ───────────────────────────────────────────────────
        Div(ProblemSectionStyle.toAttrs()) {
            Div(ProblemHeadingStyle.toAttrs()) {
                SpanText("The best mobile apps")
                Br {}
                SpanText("work without the cloud.")
            }
            Div(ProblemGridStyle.toAttrs()) {
                problemCards.forEach { card ->
                    Div(attrs = Modifier
                        .padding(2.cssRem)
                        .borderTop(1.px, LineStyle.Solid, border)
                        .toAttrs()
                    ) {
                        Span(ProblemCardNumStyle.toAttrs()) { Text(card.num) }
                        P(ProblemCardTitleStyle.toModifier().color(accent).toAttrs()) { Text(card.title) }
                        P(ProblemCardBodyStyle.toAttrs()) { Text(card.body) }
                    }
                }
            }
        }

        // ── Divider ───────────────────────────────────────────────────────────
        Div(DividerLabelStyle.toAttrs()) {
            Div(attrs = Modifier.flex(1).height(1.px).backgroundColor(border).toAttrs()) {}
            Span(DividerTextStyle.toAttrs()) { Text("The numbers") }
            Div(attrs = Modifier.flex(1).height(1.px).backgroundColor(border).toAttrs()) {}
        }

        // ── Stack / Stats ─────────────────────────────────────────────────────
        Div(StackSectionStyle.toAttrs()) {
            Div(StackHeadingStyle.toAttrs()) {
                SpanText("Production experience.")
                Br {}
                SpanText("Not just side projects.", Modifier.opacity(0.45))
            }
            Div(StackGridStyle.toAttrs()) {
                stackCards.forEach { card ->
                    Div(attrs = Modifier
                        .padding(2.cssRem)
                        .borderTop(1.px, LineStyle.Solid, border)
                        .borderLeft(1.px, LineStyle.Solid, borderFaint)
                        .toAttrs()
                    ) {
                        Span(StackStatStyle.toModifier().color(accent).toAttrs()) { Text(card.stat) }
                        Span(StackStatLabelStyle.toAttrs()) { Text(card.label) }
                        P(StackCardDescStyle.toAttrs()) { Text(card.desc) }
                    }
                }
            }
        }

        // ── Divider ───────────────────────────────────────────────────────────
        Div(DividerLabelStyle.toAttrs()) {
            Div(attrs = Modifier.flex(1).height(1.px).backgroundColor(border).toAttrs()) {}
            Span(DividerTextStyle.toAttrs()) { Text("Selected work") }
            Div(attrs = Modifier.flex(1).height(1.px).backgroundColor(border).toAttrs()) {}
        }

        // ── Projects ──────────────────────────────────────────────────────────
        Div(ProjectsSectionStyle.toAttrs()) {
            Div(ProjectsHeadingStyle.toAttrs()) { SpanText("Three apps shipped.") }
            P(ProjectsSubheadStyle.toAttrs()) { Text("All production. All on the Play Store or Amazon Appstore.") }
            projects.forEach { project ->
                Div(attrs = Modifier
                    .fillMaxWidth()
                    .display(DisplayStyle.Flex)
                    .flexDirection(FlexDirection.Column)
                    .padding(topBottom = 2.5.cssRem)
                    .borderTop(1.px, LineStyle.Solid, border)
                    .gap(1.cssRem)
                    .toAttrs()
                ) {
                    Div(ProjectRowInnerStyle.toAttrs()) {
                        Span(ProjectNumStyle.toAttrs()) { Text(project.num) }
                        Span(ProjectNameStyle.toModifier().color(accent).toAttrs()) { Text(project.name) }
                        Span(ProjectTagStyle.toAttrs()) { Text(project.tags) }
                    }
                    P(ProjectDescStyle2.toAttrs()) { Text(project.desc) }
                    A(
                        href = project.link,
                        attrs = quietLinkModifier().opacity(0.55).color(accent).toAttrs()
                    ) { Text("View Project →") }
                }
            }
        }

        // ── Divider ───────────────────────────────────────────────────────────
        Div(DividerLabelStyle.toAttrs()) {
            Div(attrs = Modifier.flex(1).height(1.px).backgroundColor(border).toAttrs()) {}
            Span(DividerTextStyle.toAttrs()) { Text("The architecture") }
            Div(attrs = Modifier.flex(1).height(1.px).backgroundColor(border).toAttrs()) {}
        }

        // ── Manifesto / Code block ─────────────────────────────────────────────
        Div(ManifestoSectionStyle.toAttrs()) {
            Div(ManifestoHeadingStyle.toAttrs()) {
                SpanText("The stack that makes")
                Br {}
                SpanText("offline AI possible.")
            }
            Pre(attrs = Modifier
                .fillMaxWidth()
                .fontFamily("'JetBrains Mono'", "monospace")
                .fontSize(0.95.cssRem)  // ↑ was 0.82
                .lineHeight(2.0)
                .padding(2.cssRem)
                .border(1.px, LineStyle.Solid, borderFaint)
                .backgroundColor(codeBg)
                .overflow(Overflow.Auto)
                .margin(bottom = 2.cssRem)
                .toAttrs()
            ) {
                Code {
                    Text(
                        "// Offline AI — inference pipeline\n\n" +
                                "model_format:         .task, .gguf, .litertlm\n" +
                                "inference_runtime:    JNI/NDK — custom C++ bridge\n" +
                                "embedding_search:     on-device semantic vector index\n" +
                                "network_permission:   NOT REQUESTED\n" +
                                "cloud_calls:          0\n" +
                                "data_location:        YOUR DEVICE\n\n" +
                                "// Android stack\n\n" +
                                "language:             Kotlin\n" +
                                "ui:                   Jetpack Compose\n" +
                                "architecture:         MVVM / MVI\n" +
                                "async:                Coroutines + Flow\n" +
                                "local_db:             Room\n" +
                                "sync:                 Retrofit + WorkManager\n" +
                                "ai_tools:             MediaPipe · OpenCV · ONNX · Gemma · Qwen"
                    )
                }
            }
        }

        // ── CTA ───────────────────────────────────────────────────────────────
        Div(attrs = Modifier
            .fillMaxWidth()
            .padding(topBottom = 4.cssRem)
            .borderTop(1.px, LineStyle.Solid, border)
            .margin(bottom = 4.cssRem)
            .toAttrs()
        ) {
            Div(CtaHeadingStyle.toAttrs()) {
                SpanText("Building something")
                Br {}
                SpanText("that needs to work offline?")
            }
            Div(CtaLinksStyle.toAttrs()) {
                A(
                    href = "mailto:samrudhakshirsagar@gmail.com",
